import { useState, useEffect, useCallback } from 'react';
import {
  Card,
  CardBody,
  CardTitle,
  CardHeader,
  CardExpandableContent,
  Label,
  Flex,
  FlexItem,
  Content,
  Progress,
  ProgressMeasureLocation,
  Divider,
  Spinner,
  Alert,
  Button,
  Icon,
  Split,
  SplitItem,
} from '@patternfly/react-core';
import {
  InProgressIcon,
  ClockIcon,
  CodeBranchIcon,
  SyncAltIcon,
} from '@patternfly/react-icons';
import { invoke } from '@tauri-apps/api/core';
import { motion } from 'motion/react';
import { useHarnessWatcher } from '../hooks/useHarnessWatcher';

interface TaskSummary {
  backlog: number;
  todo: number;
  doing: number;
  review: number;
  qa: number;
  done: number;
  total: number;
}

interface SessionInfo {
  id: string;
  started_at: string;
  title?: string;
}

interface GitInfo {
  hash: string;
  message: string;
  author: string;
  date: string;
}

interface ActiveTask {
  id: string;
  title: string;
  status: string;
}

interface ProgressCardProps {
  projectPath: string;
  onRefresh?: () => void;
}

// Execute harness CLI command via Tauri shell
async function runHarnessCommand(projectPath: string, args: string[]): Promise<string> {
  try {
    const result = await invoke<string>('run_harness_command', {
      projectPath,
      args,
    });
    return result;
  } catch (error) {
    console.error('Failed to run harness command:', error);
    throw error;
  }
}

// Parse task summary from harness status --json
function parseTaskSummary(json: string): TaskSummary | null {
  try {
    const data = JSON.parse(json);
    if (data.tasks) {
      return {
        backlog: data.tasks.backlog || 0,
        todo: data.tasks.todo || 0,
        doing: data.tasks.doing || 0,
        review: data.tasks.review || 0,
        qa: data.tasks.qa || 0,
        done: data.tasks.done || 0,
        total: data.tasks.total || 0,
      };
    }
    return null;
  } catch {
    return null;
  }
}

// Parse session info from harness session current --json
function parseSessionInfo(json: string): SessionInfo | null {
  try {
    const data = JSON.parse(json);
    if (data.id) {
      return {
        id: data.id,
        started_at: data.started_at,
        title: data.title,
      };
    }
    return null;
  } catch {
    return null;
  }
}

// Format relative time
function formatRelativeTime(isoDate: string): string {
  const date = new Date(isoDate);
  const now = new Date();
  const diff = now.getTime() - date.getTime();
  const minutes = Math.floor(diff / 60000);
  const hours = Math.floor(diff / 3600000);

  if (minutes < 1) return 'Just now';
  if (minutes < 60) return `${minutes}m ago`;
  if (hours < 24) return `${hours}h ago`;
  return date.toLocaleDateString();
}

export function ProgressCard({
  projectPath,
  onRefresh,
}: ProgressCardProps): React.JSX.Element {
  const [isExpanded, setIsExpanded] = useState(true);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [taskSummary, setTaskSummary] = useState<TaskSummary | null>(null);
  const [session, setSession] = useState<SessionInfo | null>(null);
  const [gitInfo, setGitInfo] = useState<GitInfo | null>(null);
  const [activeTasks, setActiveTasks] = useState<ActiveTask[]>([]);

  const fetchData = useCallback(async () => {
    setIsLoading(true);
    setError(null);

    try {
      // Get task summary via harness status --json
      try {
        const statusJson = await runHarnessCommand(projectPath, ['status', '--format', 'json']);
        const summary = parseTaskSummary(statusJson);
        if (summary) {
          setTaskSummary(summary);
        }
      } catch (e) {
        console.error('Failed to get status:', e);
      }

      // Get current session via harness session current --json
      try {
        const sessionJson = await runHarnessCommand(projectPath, ['session', 'current', '--format', 'json']);
        const sessionData = parseSessionInfo(sessionJson);
        setSession(sessionData);
      } catch {
        setSession(null);
      }

      // Get active (doing) tasks
      try {
        const tasksJson = await runHarnessCommand(projectPath, ['task', 'list', '--status', 'doing', '--format', 'json']);
        const tasks = JSON.parse(tasksJson);
        if (Array.isArray(tasks)) {
          setActiveTasks(tasks.slice(0, 3).map((t: { id: string; title: string; status: string }) => ({
            id: t.id,
            title: t.title,
            status: t.status,
          })));
        }
      } catch {
        setActiveTasks([]);
      }

      // Get git info
      try {
        const gitResult = await invoke<string>('get_git_info', { projectPath });
        if (gitResult) {
          const parsed = JSON.parse(gitResult);
          setGitInfo(parsed);
        }
      } catch {
        setGitInfo(null);
      }
    } catch (e) {
      setError('Failed to load project status');
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  }, [projectPath]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  // Auto-refresh when .harness files change (F008)
  // TEMPORARILY DISABLED - causing loop, needs investigation
  // useHarnessWatcher({
  //   projectPath,
  //   onChange: fetchData,
  //   enabled: !!projectPath,
  // });

  const handleRefresh = useCallback(() => {
    fetchData();
    onRefresh?.();
  }, [fetchData, onRefresh]);

  const completionPercent = taskSummary
    ? Math.round((taskSummary.done / Math.max(taskSummary.total, 1)) * 100)
    : 0;

  return (
    <Card isExpanded={isExpanded}>
      <CardHeader
        onExpand={() => setIsExpanded(!isExpanded)}
        isToggleRightAligned
        toggleButtonProps={{
          'aria-label': isExpanded ? 'Collapse progress' : 'Expand progress',
        }}
        actions={{
          actions: (
            <Button
              variant="plain"
              aria-label="Refresh"
              onClick={handleRefresh}
              isDisabled={isLoading}
            >
              <SyncAltIcon />
            </Button>
          ),
        }}
      >
        <CardTitle>
          <Flex alignItems={{ default: 'alignItemsCenter' }} gap={{ default: 'gapSm' }}>
            <FlexItem>Project Progress</FlexItem>
            {taskSummary && (
              <FlexItem>
                <Label color="blue" isCompact>
                  {taskSummary.done}/{taskSummary.total}
                </Label>
              </FlexItem>
            )}
          </Flex>
        </CardTitle>
      </CardHeader>
      <CardExpandableContent>
        <CardBody>
          {isLoading ? (
            <Flex justifyContent={{ default: 'justifyContentCenter' }}>
              <Spinner size="lg" />
            </Flex>
          ) : error ? (
            <Alert variant="warning" title="Unable to load progress" isInline>
              {error}
            </Alert>
          ) : (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ duration: 0.2 }}
            >
              {/* Progress bar */}
              {taskSummary && (
                <>
                  <Progress
                    value={completionPercent}
                    title="Completion"
                    measureLocation={ProgressMeasureLocation.top}
                    label={`${completionPercent}% complete`}
                  />

                  {/* Status breakdown */}
                  <Flex
                    gap={{ default: 'gapSm' }}
                    style={{ marginTop: 16, marginBottom: 16, flexWrap: 'wrap' }}
                  >
                    {taskSummary.backlog > 0 && (
                      <FlexItem>
                        <Label color="grey" isCompact>
                          Backlog: {taskSummary.backlog}
                        </Label>
                      </FlexItem>
                    )}
                    {taskSummary.todo > 0 && (
                      <FlexItem>
                        <Label color="blue" isCompact>
                          Todo: {taskSummary.todo}
                        </Label>
                      </FlexItem>
                    )}
                    {taskSummary.doing > 0 && (
                      <FlexItem>
                        <Label color="orange" isCompact>
                          Doing: {taskSummary.doing}
                        </Label>
                      </FlexItem>
                    )}
                    {taskSummary.review > 0 && (
                      <FlexItem>
                        <Label color="purple" isCompact>
                          Review: {taskSummary.review}
                        </Label>
                      </FlexItem>
                    )}
                    {taskSummary.qa > 0 && (
                      <FlexItem>
                        <Label color="teal" isCompact>
                          QA: {taskSummary.qa}
                        </Label>
                      </FlexItem>
                    )}
                    <FlexItem>
                      <Label color="green" isCompact>
                        Done: {taskSummary.done}
                      </Label>
                    </FlexItem>
                  </Flex>
                </>
              )}

              {/* Active tasks */}
              {activeTasks.length > 0 && (
                <>
                  <Divider style={{ marginBottom: 16 }} />
                  <Content component="h4" style={{ marginBottom: 8 }}>
                    <Icon status="warning" size="sm">
                      <InProgressIcon />
                    </Icon>{' '}
                    Currently Working On
                  </Content>
                  {activeTasks.map((task) => (
                    <Split key={task.id} hasGutter style={{ marginBottom: 4 }}>
                      <SplitItem>
                        <Label color="orange" isCompact>
                          {task.id}
                        </Label>
                      </SplitItem>
                      <SplitItem isFilled>
                        <Content component="small">{task.title}</Content>
                      </SplitItem>
                    </Split>
                  ))}
                </>
              )}

              {/* Session info */}
              {session && (
                <>
                  <Divider style={{ marginTop: 16, marginBottom: 16 }} />
                  <Split hasGutter>
                    <SplitItem>
                      <Icon status="info" size="sm">
                        <ClockIcon />
                      </Icon>
                    </SplitItem>
                    <SplitItem isFilled>
                      <Content component="small">
                        Session started {formatRelativeTime(session.started_at)}
                        {session.title && `: ${session.title}`}
                      </Content>
                    </SplitItem>
                  </Split>
                </>
              )}

              {/* Git info */}
              {gitInfo && (
                <Split hasGutter style={{ marginTop: 8 }}>
                  <SplitItem>
                    <Icon status="info" size="sm">
                      <CodeBranchIcon />
                    </Icon>
                  </SplitItem>
                  <SplitItem isFilled>
                    <Content component="small">
                      <code style={{ fontSize: '0.85em' }}>{gitInfo.hash.substring(0, 7)}</code>
                      {' '}{gitInfo.message}
                    </Content>
                  </SplitItem>
                </Split>
              )}

              {/* No data state */}
              {!taskSummary && !session && !gitInfo && (
                <Alert variant="info" title="No harness data" isInline>
                  <Content component="small">
                    This project doesn't have harness data yet. Run <code>harness init</code> to get started.
                  </Content>
                </Alert>
              )}
            </motion.div>
          )}
        </CardBody>
      </CardExpandableContent>
    </Card>
  );
}

export default ProgressCard;

