import { useState, useCallback, useEffect } from 'react';
import {
  Card,
  CardBody,
  CardTitle,
  CardHeader,
  Gallery,
  GalleryItem,
  Modal,
  ModalVariant,
  ModalHeader,
  ModalBody,
  EmptyState,
  EmptyStateBody,
  Spinner,
  Flex,
  FlexItem,
  Label,
  Content,
} from '@patternfly/react-core';
import { ImageIcon } from '@patternfly/react-icons';
import { invoke } from '@tauri-apps/api/core';
import { motion } from 'motion/react';

interface Screenshot {
  id: string;
  task_id: string | null;
  step_id: string | null;
  file_name: string;
  caption: string | null;
  created_at: string;
}

interface ScreenshotViewerProps {
  projectPath: string;
  taskId?: string;
  maxItems?: number;
}

// Get screenshots via harness CLI
async function getScreenshots(
  projectPath: string,
  taskId?: string,
  limit?: number
): Promise<Screenshot[]> {
  try {
    const args = ['screenshot', 'list', '--format', 'json'];
    if (taskId) {
      args.push('--task', taskId);
    }
    if (limit) {
      args.push('--limit', String(limit));
    }

    const result = await invoke<string>('run_harness_command', {
      projectPath,
      args,
    });

    return JSON.parse(result) as Screenshot[];
  } catch (error) {
    console.error('Failed to get screenshots:', error);
    return [];
  }
}

// Format date for display
function formatDate(isoDate: string): string {
  const date = new Date(isoDate);
  return date.toLocaleDateString(undefined, {
    month: 'short',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  });
}

export function ScreenshotViewer({
  projectPath,
  taskId,
  maxItems = 20,
}: ScreenshotViewerProps): React.JSX.Element {
  const [screenshots, setScreenshots] = useState<Screenshot[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [selectedScreenshot, setSelectedScreenshot] = useState<Screenshot | null>(null);

  const fetchScreenshots = useCallback(async () => {
    setIsLoading(true);
    try {
      const items = await getScreenshots(projectPath, taskId, maxItems);
      setScreenshots(items);
    } catch (error) {
      console.error('Failed to fetch screenshots:', error);
    } finally {
      setIsLoading(false);
    }
  }, [projectPath, taskId, maxItems]);

  useEffect(() => {
    fetchScreenshots();
  }, [fetchScreenshots]);

  const handleClose = useCallback(() => {
    setSelectedScreenshot(null);
  }, []);

  if (isLoading) {
    return (
      <Card>
        <CardBody>
          <Flex justifyContent={{ default: 'justifyContentCenter' }}>
            <Spinner size="lg" />
          </Flex>
        </CardBody>
      </Card>
    );
  }

  if (screenshots.length === 0) {
    return (
      <Card>
        <CardBody>
          <EmptyState>
            <Content component="h4">No screenshots</Content>
            <EmptyStateBody>
              No visual test screenshots have been captured yet.
              Run visual tests to capture screenshots.
            </EmptyStateBody>
          </EmptyState>
        </CardBody>
      </Card>
    );
  }

  return (
    <>
      <Card>
        <CardHeader>
          <CardTitle>
            <Flex alignItems={{ default: 'alignItemsCenter' }} gap={{ default: 'gapSm' }}>
              <FlexItem>Screenshots</FlexItem>
              <FlexItem>
                <Label color="blue" isCompact>
                  {screenshots.length}
                </Label>
              </FlexItem>
            </Flex>
          </CardTitle>
        </CardHeader>
        <CardBody>
          <Gallery hasGutter minWidths={{ default: '150px' }}>
            {screenshots.map((screenshot) => (
              <GalleryItem key={screenshot.id}>
                <motion.div
                  initial={{ opacity: 0, scale: 0.95 }}
                  animate={{ opacity: 1, scale: 1 }}
                  transition={{ duration: 0.2 }}
                  whileHover={{ scale: 1.02 }}
                  style={{ cursor: 'pointer' }}
                  onClick={() => setSelectedScreenshot(screenshot)}
                >
                  <Card isCompact>
                    <CardBody style={{ padding: 8 }}>
                      <div
                        style={{
                          aspectRatio: '16/9',
                          backgroundColor: 'var(--pf-t--global--background--color--secondary--default)',
                          borderRadius: 4,
                          overflow: 'hidden',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                        }}
                      >
                        <ImageIcon
                          style={{
                            fontSize: 32,
                            color: 'var(--pf-t--global--color--nonstatus--gray--default)',
                          }}
                        />
                      </div>
                      <div style={{ marginTop: 8 }}>
                        <div
                          style={{
                            fontSize: '0.75rem',
                            fontWeight: 500,
                            overflow: 'hidden',
                            textOverflow: 'ellipsis',
                            whiteSpace: 'nowrap',
                          }}
                        >
                          {screenshot.caption || screenshot.file_name}
                        </div>
                        <div
                          style={{
                            fontSize: '0.7rem',
                            color: 'var(--pf-t--global--color--nonstatus--gray--default)',
                          }}
                        >
                          {formatDate(screenshot.created_at)}
                        </div>
                      </div>
                    </CardBody>
                  </Card>
                </motion.div>
              </GalleryItem>
            ))}
          </Gallery>
        </CardBody>
      </Card>

      {/* Lightbox Modal */}
      <Modal
        isOpen={selectedScreenshot !== null}
        onClose={handleClose}
        variant={ModalVariant.large}
        aria-label="Screenshot viewer"
      >
        {selectedScreenshot && (
          <>
            <ModalHeader
              title={selectedScreenshot.caption || selectedScreenshot.file_name}
              titleIconVariant="info"
            />
            <ModalBody>
              <div
                style={{
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  gap: 16,
                }}
              >
                <div
                  style={{
                    maxWidth: '100%',
                    maxHeight: '60vh',
                    backgroundColor: 'var(--pf-t--global--background--color--secondary--default)',
                    borderRadius: 8,
                    padding: 16,
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    minHeight: 300,
                  }}
                >
                  <ImageIcon
                    style={{
                      fontSize: 64,
                      color: 'var(--pf-t--global--color--nonstatus--gray--default)',
                    }}
                  />
                </div>
                <Flex gap={{ default: 'gapMd' }}>
                  <FlexItem>
                    <Label color="grey" isCompact>
                      {selectedScreenshot.file_name}
                    </Label>
                  </FlexItem>
                  <FlexItem>
                    <Label color="blue" isCompact>
                      {formatDate(selectedScreenshot.created_at)}
                    </Label>
                  </FlexItem>
                  {selectedScreenshot.task_id && (
                    <FlexItem>
                      <Label color="orange" isCompact>
                        Task: {selectedScreenshot.task_id.slice(0, 8)}...
                      </Label>
                    </FlexItem>
                  )}
                </Flex>
              </div>
            </ModalBody>
          </>
        )}
      </Modal>
    </>
  );
}

export default ScreenshotViewer;

